<script setup>
import{reactive,ref}from'vue';import{Head,Link}from'@inertiajs/vue3';import axios from'axios';
const props=defineProps({participant:Object,profile:Object,entries:Array,versions:Array});const items=ref(JSON.parse(JSON.stringify(props.entries||[])));const versionItems=ref([...props.versions]);const blank=()=>({type:'experience',title:'',organization:'',location:'',starts_at:'',ends_at:'',current:false,description:'',proficiency:'',sort_order:items.value.length});const form=reactive(blank());const labels={experience:'Berufserfahrung',education:'Bildung',qualification:'Qualifikation',language:'Sprache',skill:'Kenntnis'};const payload=(e)=>({...e,organization:e.organization||null,location:e.location||null,starts_at:e.starts_at?.slice(0,10)||null,ends_at:e.current?null:e.ends_at?.slice(0,10)||null,description:e.description||null,proficiency:e.proficiency||null,current:Boolean(e.current),sort_order:e.sort_order||0});const create=async()=>{const r=await axios.post(route('participant-portal.resume.entries.store'),payload(form));items.value.push(r.data.entry);Object.assign(form,blank());};const save=async(e)=>{const r=await axios.put(route('participant-portal.resume.entries.update',e.id),payload(e));Object.assign(e,r.data.entry);};const remove=async(e)=>{await axios.delete(route('participant-portal.resume.entries.destroy',e.id));items.value=items.value.filter(i=>i.id!==e.id);};const versionLabel=ref('');const createVersion=async()=>{const r=await axios.post(route('participant-portal.resume.versions.store'),{label:versionLabel.value||null});versionItems.value.unshift(r.data.version);versionLabel.value='';};
</script>
<template><Head title="Lebenslauf"/><main class="min-h-screen bg-sky-50 px-5 py-8"><div class="mx-auto max-w-6xl space-y-6"><header class="flex justify-between"><div><p class="text-xs font-semibold uppercase tracking-widest text-zbb">Matrix Teilnehmerportal</p><h1 class="text-2xl font-bold">Mein Lebenslauf</h1><p class="text-sm text-gray-500">{{ participant.vorname }} {{ participant.nachname }} · {{ profile?.professional_headline }}</p></div><Link :href="route('participant-portal.dashboard')" class="rounded border bg-white px-4 py-2">Dashboard</Link></header><section class="rounded-2xl border bg-white p-6 shadow"><h2 class="font-semibold">Eintrag hinzufügen</h2><div class="mt-4 grid gap-3 md:grid-cols-3"><select v-model="form.type" class="rounded border-gray-300"><option v-for="(label,key) in labels" :key="key" :value="key">{{ label }}</option></select><input v-model="form.title" placeholder="Bezeichnung" class="rounded border-gray-300"/><input v-model="form.organization" placeholder="Organisation / Arbeitgeber" class="rounded border-gray-300"/><input v-model="form.location" placeholder="Ort" class="rounded border-gray-300"/><input v-model="form.starts_at" type="date" class="rounded border-gray-300"/><input v-model="form.ends_at" type="date" :disabled="form.current" class="rounded border-gray-300"/><input v-model="form.proficiency" placeholder="Niveau, z. B. B2" class="rounded border-gray-300"/><label><input v-model="form.current" type="checkbox"/> aktuell</label><textarea v-model="form.description" placeholder="Beschreibung" class="rounded border-gray-300 md:col-span-3"></textarea></div><button class="mt-3 rounded bg-zbb px-4 py-2 text-white" @click="create">Hinzufügen</button></section><section class="rounded-2xl border bg-white p-6 shadow"><h2 class="font-semibold">Einträge</h2><div class="mt-4 space-y-3"><article v-for="entry in items" :key="entry.id" class="rounded-xl border p-4"><div class="grid gap-3 md:grid-cols-3"><select v-model="entry.type" class="rounded border-gray-300"><option v-for="(label,key) in labels" :key="key" :value="key">{{ label }}</option></select><input v-model="entry.title" class="rounded border-gray-300"/><input v-model="entry.organization" class="rounded border-gray-300"/><input v-model="entry.location" class="rounded border-gray-300"/><input v-model="entry.starts_at" type="date" class="rounded border-gray-300"/><input v-model="entry.ends_at" type="date" :disabled="entry.current" class="rounded border-gray-300"/><input v-model="entry.proficiency" class="rounded border-gray-300"/><label><input v-model="entry.current" type="checkbox"/> aktuell</label><textarea v-model="entry.description" class="rounded border-gray-300 md:col-span-3"></textarea></div><div class="mt-3 flex gap-3"><button class="text-zbb" @click="save(entry)">Speichern</button><button class="text-red-600" @click="remove(entry)">Löschen</button></div></article><p v-if="!items.length" class="text-sm text-gray-500">Noch keine strukturierten Einträge.</p></div></section><section class="rounded-2xl border bg-white p-6 shadow"><h2 class="font-semibold">Versionen und Export</h2><div class="mt-3 flex gap-3"><input v-model="versionLabel" placeholder="Optionale Bezeichnung" class="flex-1 rounded border-gray-300"/><button class="rounded bg-green-700 px-4 py-2 text-white" @click="createVersion">Aktuellen Stand versionieren</button></div><div class="mt-4 space-y-2"><article v-for="version in versionItems" :key="version.id" class="flex flex-wrap items-center justify-between gap-3 rounded border p-3"><div><p class="font-semibold">Version {{ version.version }} · {{ version.label||'ohne Bezeichnung' }}</p><p class="text-xs text-gray-500">{{ new Date(version.created_at).toLocaleString('de-DE') }} · SHA-256 {{ version.snapshot_sha256 }}</p></div><div class="flex gap-2"><a :href="route('participant-portal.resume.versions.download',version.id)" class="rounded border px-3 py-2 text-sm">JSON</a><Link :href="route('participant-portal.resume.versions.print',version.id)" class="rounded border px-3 py-2 text-sm">Druckansicht</Link></div></article></div></section></div></main></template>
